        for fn in fns:
            x = fn(x)
        return x
    return piped

class LRUCache:
    def __init__(self, cap):
        self.cap = cap
        self.cache = OrderedDict()
    def get(self, key):
        if key not in self.cache: return -1
        self.cache.move_to_end(key)
        return self.cache[key]
    def put(self, key, val):
        if key in self.cache: self.cache.move_to_end(key)
        self.cache[key] = val
        if len(self.cache) > self.cap: self.cache.popitem(last=False)

def zip_longest(*iterables, fillvalue=None):
    iters = [iter(it) for it in iterables]
    while True:
        values = []
        all_done = True
        for it in iters:
            try:
                values.append(next(it))
                all_done = False
            except StopIteration:
                values.append(fillvalue)
        if all_done: return
        yield tuple(values)

class EventEmitter:
    def __init__(self):
        self._events = {}
    def on(self, event, fn):
        self._events.setdefault(event, []).append(fn)
    def emit(self, event, *args):
        for fn in self._events.get(event, []): fn(*args)
    def off(self, event, fn):
        self._events.get(event, []).remove(fn)

def knapsack(weights, values, capacity):
    n = len(weights)
    dp = [[0]*(capacity+1) for _ in range(n+1)]
    for i in range(1, n+1):
        for w in range(capacity+1):
            dp[i][w] = dp[i-1][w]
            if weights[i-1] <= w:
                dp[i][w] = max(dp[i][w], dp[i-1][w-weights[i-1]] + values[i-1])
    return dp[n][capacity]

def sliding_window_max(nums, k):
    dq, result = collections.deque(), []
    for i, n in enumerate(nums):
        while dq and dq[0] < i - k + 1: dq.popleft()
        while dq and nums[dq[-1]] < n: dq.pop()
        dq.append(i)
        if i >= k - 1: result.append(nums[dq[0]])
    return result

def longest_common_subsequence(a, b):
    m, n = len(a), len(b)
    dp = [[0]*(n+1) for _ in range(m+1)]
    for i in range(1, m+1):
        for j in range(1, n+1):
            if a[i-1] == b[j-1]: dp[i][j] = dp[i-1][j-1] + 1
            else: dp[i][j] = max(dp[i-1][j], dp[i][j-1])
    return dp[m][n]

def curry(fn):
    import inspect
    n = len(inspect.signature(fn).parameters)
    def curried(*args):
        if len(args) >= n: return fn(*args)
        return lambda *more: curried(*args, *more)
    return curried

class BloomFilter:
    def __init__(self, size, num_hashes):
        self.bits = [False] * size
        self.size = size
        self.num_hashes = num_hashes
    def _hashes(self, item):
        return [hash(str(item) + str(i)) % self.size for i in range(self.num_hashes)]
    def add(self, item):
        for h in self._hashes(item): self.bits[h] = True
    def __contains__(self, item):
        return all(self.bits[h] for h in self._hashes(item))

def a_star(graph, start, goal, heuristic):
    open_set = [(heuristic(start, goal), 0, start, [start])]
    visited = set()
    while open_set:
        _, cost, node, path = heapq.heappop(open_set)
        if node == goal: return path
        if node in visited: continue
        visited.add(node)
        for neighbor, weight in graph[node]:
            if neighbor not in visited:
                new_cost = cost + weight
                heapq.heappush(open_set, (new_cost + heuristic(neighbor, goal), new_cost, neighbor, path + [neighbor]))
    return None

def union_find(n):
    parent = list(range(n))
    rank = [0] * n
    def find(x):
        if parent[x] != x: parent[x] = find(parent[x])
        return parent[x]
    def union(x, y):
        px, py = find(x), find(y)
        if px == py: return
        if rank[px] < rank[py]: px, py = py, px
        parent[py] = px
        if rank[px] == rank[py]: rank[px] += 1
    return find, union

