def consistent_hash(nodes, replicas=100):
    ring = {}
    for node in nodes:
        for i in range(replicas):
            key = hash(f'{node}:{i}')
            ring[key] = node
    sorted_keys = sorted(ring.keys())
    def get_node(item):
        h = hash(item)
        idx = bisect.bisect(sorted_keys, h) % len(sorted_keys)
        return ring[sorted_keys[idx]]
    return get_node

