class CircuitBreaker:
    def __init__(self, threshold=5, timeout=30):
        self.threshold = threshold
        self.timeout = timeout
        self.failures = 0
        self.last_failure = 0
        self.state = 'closed'
    def call(self, fn):
        if self.state == 'open':
            if time.time() - self.last_failure > self.timeout:
                self.state = 'half-open'
            else: raise Exception('Circuit open')
        try:
            result = fn()
            self.failures = 0
            self.state = 'closed'
            return result
        except Exception:
            self.failures += 1
            self.last_failure = time.time()
            if self.failures >= self.threshold: self.state = 'open'
            raise

def crc32(data):
    crc = 0xFFFFFFFF
    for byte in data:
        crc ^= byte
        for _ in range(8):
            if crc & 1: crc = (crc >> 1) ^ 0xEDB88320
            else: crc >>= 1
    return crc ^ 0xFFFFFFFF

class AsyncQueue:
    def __init__(self, maxsize=0):
        self._queue = collections.deque()
        self._maxsize = maxsize
        self._getters = collections.deque()
        self._putters = collections.deque()
    async def put(self, item):
        while self._maxsize and len(self._queue) >= self._maxsize:
            putter = asyncio.get_event_loop().create_future()
            self._putters.append(putter)
            await putter
        self._queue.append(item)
        if self._getters:
            self._getters.popleft().set_result(None)
    async def get(self):
        while not self._queue:
            getter = asyncio.get_event_loop().create_future()
            self._getters.append(getter)
            await getter
        return self._queue.popleft()

def tokenize(expression):
    tokens, i = [], 0
    while i < len(expression):
        if expression[i].isspace(): i += 1
        elif expression[i].isdigit():
            j = i
            while j < len(expression) and (expression[j].isdigit() or expression[j] == '.'): j += 1
            tokens.append(('NUM', float(expression[i:j])))
            i = j
        elif expression[i] in '+-*/()': tokens.append(('OP', expression[i])); i += 1
        else: raise ValueError(f'Unexpected: {expression[i]}')
    return tokens

class Middleware:
