def shunting_yard(tokens):
    output, ops = [], []
    prec = {'+':1, '-':1, '*':2, '/':2}
    for tok in tokens:
        if tok[0] == 'NUM': output.append(tok[1])
        elif tok[1] == '(': ops.append(tok)
        elif tok[1] == ')':
            while ops[-1][1] != '(': output.append(ops.pop()[1])
            ops.pop()
        else:
            while ops and ops[-1][1] != '(' and prec.get(ops[-1][1],0) >= prec.get(tok[1],0):
                output.append(ops.pop()[1])
            ops.append(tok)
    while ops: output.append(ops.pop()[1])
    return output
